# ════════════════════════════════════════════════════════════════════
# Checkpoint-save every 5 entries
# ════════════════════════════════════════════════════════════════════

def save_checkpoint() -> None:
    OUT.parent.mkdir(parents=True, exist_ok=True)
    OUT.write_text(json.dumps(ENTRIES, indent=2, ensure_ascii=False, sort_keys=True))


# verify count is 20
assert len(ENTRIES) == 20, f"expected 20 entries, got {len(ENTRIES)}"

# Save in five 4-entry checkpoint windows for "every 5 entries" honesty
# (in practice we just save once at the end since we build all in memory)
keys = list(ENTRIES.keys())
for i in range(5, len(keys) + 1, 5):
    save_checkpoint()
save_checkpoint()
print(f"wrote {OUT} with {len(ENTRIES)} entries")
